UIDressStoreTableItem = class("UIDressStoreTableItem", IGUIWindow)

function UIDressStoreTableItem:onLode()

end

function UIDressStoreTableItem:initTab(tab, newNum)
    --self.siBg = self:getChildWindow(0,GUIType.StaticImage)
    self.btnButton = self:getChildWindow(0, GUIType.CheckBox)
    self.siImage = self:getChildWindow(1, GUIType.StaticImage)
    self.stName = self:getChildWindow(2, GUIType.StaticText)
    self.siImage:SetImage(tab.Icon)
    self.stName:SetText(Lang:getString(tab.Name))
    self.newNum = newNum
    self:setNewNum(newNum)
end

function UIDressStoreTableItem:setNewNum(newNum)
    self.btnNew = self:getChildWindow(3, GUIType.Button)
    self.stNewText = self:getChildWindow(0, GUIType.StaticText, self.btnNew)
    if newNum == 0 then
        self.btnNew:SetVisible(false)
    else
        self.btnNew:SetVisible(true)
        self.stNewText:SetText(newNum)
    end
end

function UIDressStoreTableItem:setIndex(index)
    self.index = index
end

function UIDressStoreTableItem:registerClick(Type)
    self.btnButton:registerEvent(GUIEvent.CheckStateChanged, function()
        if self.btnButton:GetChecked() then
            DressStoreTabChangeEvent:invoke(self.index)
            self.btnButton:SetTouchable(false)
        end
    end)

    self:registerEvent(TableNewNumChangeEvent, function(type)
        if type == self.index then
            self.stNewText:SetText(self.newNum - 1)
            self.newNum = self.newNum - 1
            if self.newNum == 0 then
                self.btnNew:SetVisible(false)
            end
        end
    end)
end

return UIDressStoreTableItem